package qrspicmd

import (
	"context"
	"errors"
	"os"
	"path/filepath"
	"strings"
)

type ChildRunRequest struct {
	ID                   string
	Stage                string
	Cwd                  string
	ManagerRunID         string
	PromptFile           string
	OutputPath           string
	SessionID            string
	SessionDir           string
	SessionName          string
	DonePath             string
	StatusPath           string
	ValidationStatusPath string
	Split                string
	ParentPaneID         string
	StateFile            string
	PlanDir              string
	ExtensionPath        string
	PiModel              string
}

type ChildRun struct {
	ID         string
	Pane       TmuxPane
	OutputPath string
	SessionID  string
	SessionDir string
	DonePath   string
	StatusPath string
}

type ChildRunResult struct {
	ID          string
	ExitCode    int
	OutputPath  string
	SessionID   string
	SessionDir  string
	SessionPath string
	DonePath    string
	StatusPath  string
}

type ChildStatus struct {
	ExitCode   int    `json:"exitCode"`
	FinishedAt string `json:"finishedAt,omitempty"`
}

type ChildTurnStatus struct {
	Event      string `json:"event"`
	Stage      string `json:"stage"`
	ChildID    string `json:"childId"`
	StateFile  string `json:"stateFile"`
	PlanDir    string `json:"planDir"`
	SessionID  string `json:"sessionId"`
	SessionDir string `json:"sessionDir"`
	FinishedAt string `json:"finishedAt"`
	WakeTarget string `json:"wakeTarget"`
}

type TmuxSplitRequest struct {
	Cwd          string
	Direction    string
	Command      []string
	TargetPaneID string
}

type TmuxPane struct{ ID string }

func ResultPath(root, childID string) string {
	return filepath.Join(root, "runs", childID, "result.txt")
}

func OutputPath(root, childID string) string {
	return filepath.Join(root, "runs", childID, "output.txt")
}

func SessionDir(root, childID string) string {
	return filepath.Join(root, "runs", childID, "sessions")
}

func DonePath(root, childID string) string {
	return filepath.Join(root, "runs", childID, "done")
}

func StatusPath(root, childID string) string {
	return filepath.Join(root, "runs", childID, "status.json")
}

func ValidationStatusPath(root, childID string) string {
	return filepath.Join(root, "runs", childID, "validation-status.json")
}

func ChildSessionID(childID string) string {
	clean := strings.NewReplacer("/", "-", " ", "-", "_", "-").
		Replace(strings.TrimSpace(childID))
	clean = strings.Trim(clean, "-.")
	if clean == "" {
		return "q-manager-child"
	}
	return clean
}

func BuildChildCommand(req ChildRunRequest) []string {
	piCommand := `pi "${PI_MODEL_ARGS[@]}" --session-id "$SESSION_ID" --session-dir "$SESSION_DIR" --name "$SESSION_NAME" "@$PROMPT_FILE"`
	if strings.TrimSpace(req.ExtensionPath) != "" {
		piCommand = `pi "${PI_MODEL_ARGS[@]}" --extension "$Q_MANAGER_CHILD_EXTENSION" --session-id "$SESSION_ID" --session-dir "$SESSION_DIR" --name "$SESSION_NAME" "@$PROMPT_FILE"`
	}
	script := `set -o pipefail
printf 'q-manager child starting\n'
printf 'stage: %s\n' "$STAGE"
printf 'cwd: %s\n' "$PWD"
printf 'session id: %s\n' "$SESSION_ID"
printf 'session dir: %s\n' "$SESSION_DIR"
printf 'prompt: %s\n' "$PROMPT_FILE"
printf 'output: %s\n' "$OUTPUT_PATH"
printf 'mode: interactive Pi; exit child Pi after final qrspi_result so q-manager can validate\n\n'
PI_MODEL_ARGS=()
if [ -n "${VAMOS_PI_MODEL:-}" ]; then
  PI_MODEL_ARGS=(--model "$VAMOS_PI_MODEL")
  printf 'pi model: %s\n' "$VAMOS_PI_MODEL"
fi
: > "$OUTPUT_PATH"
` + piCommand + `
status=$?
if [ -n "${TMUX_PANE:-}" ]; then
  tmux capture-pane -p -t "$TMUX_PANE" -S - > "$OUTPUT_PATH" 2>/dev/null || true
fi
printf '{"exitCode":%d,"finishedAt":"%s"}\n' "$status" "$(date -u +%Y-%m-%dT%H:%M:%SZ)" > "$STATUS_PATH"
touch "$DONE_PATH"
exit "$status"`
	return []string{
		"env",
		"STAGE=" + req.Stage,
		"PROMPT_FILE=" + req.PromptFile,
		"OUTPUT_PATH=" + req.OutputPath,
		"SESSION_ID=" + req.SessionID,
		"SESSION_DIR=" + req.SessionDir,
		"SESSION_NAME=" + req.SessionName,
		"DONE_PATH=" + req.DonePath,
		"STATUS_PATH=" + req.StatusPath,
		"Q_MANAGER_PARENT_PANE=" + req.ParentPaneID,
		"Q_MANAGER_STATE_FILE=" + req.StateFile,
		"Q_MANAGER_PLAN_DIR=" + req.PlanDir,
		"Q_MANAGER_STAGE=" + req.Stage,
		"Q_MANAGER_MANAGER_RUN_ID=" + req.ManagerRunID,
		"Q_MANAGER_CHILD_ID=" + req.ID,
		"Q_MANAGER_DONE_PATH=" + req.DonePath,
		"Q_MANAGER_STATUS_PATH=" + req.StatusPath,
		"Q_MANAGER_VALIDATED_STATUS_PATH=" + req.ValidationStatusPath,
		"Q_MANAGER_WAKE_MODE=validated-only",
		"Q_MANAGER_SESSION_ID=" + req.SessionID,
		"Q_MANAGER_SESSION_DIR=" + req.SessionDir,
		"Q_MANAGER_CHILD_EXTENSION=" + req.ExtensionPath,
		"VAMOS_PI_MODEL=" + strings.TrimSpace(req.PiModel),
		"bash",
		"-lc",
		script,
	}
}

type TmuxChildRunner struct{ Tmux TmuxClient }

func (r TmuxChildRunner) Start(
	ctx context.Context,
	req ChildRunRequest,
) (ChildRun, error) {
	if r.Tmux == nil {
		return ChildRun{}, errors.New("tmux client is required")
	}
	pane, err := r.Tmux.SplitPane(
		ctx,
		TmuxSplitRequest{
			Cwd:          req.Cwd,
			Direction:    req.Split,
			Command:      BuildChildCommand(req),
			TargetPaneID: req.ParentPaneID,
		},
	)
	if err != nil {
		return ChildRun{}, err
	}
	return ChildRun{
		ID:         req.ID,
		Pane:       pane,
		OutputPath: req.OutputPath,
		SessionID:  req.SessionID,
		SessionDir: req.SessionDir,
		DonePath:   req.DonePath,
		StatusPath: req.StatusPath,
	}, nil
}

func (r TmuxChildRunner) Wait(ctx context.Context, run ChildRun) (ChildRunResult, error) {
	select {
	case <-ctx.Done():
		return ChildRunResult{}, ctx.Err()
	default:
	}
	return ChildRunResult{
		ID:         run.ID,
		OutputPath: run.OutputPath,
		SessionID:  run.SessionID,
		SessionDir: run.SessionDir,
		DonePath:   run.DonePath,
		StatusPath: run.StatusPath,
	}, nil
}

func ensureRunFiles(req ChildRunRequest) error {
	for _, dir := range []string{filepath.Dir(req.OutputPath), req.SessionDir, filepath.Dir(req.DonePath), filepath.Dir(req.StatusPath), filepath.Dir(req.ValidationStatusPath)} {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return err
		}
	}
	return nil
}

package qrspicmd

import (
	"context"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/CoreyCole/vamos/pkg/agents/workflows/qrspi"
	wruntime "github.com/CoreyCole/vamos/pkg/agents/workflows/runtime"
)

func resolveOrInitStartState(
	ctx context.Context,
	opts StartNextOptions,
	d deps,
) (ManagerState, string, error) {
	clock := d.Clock
	if clock == nil {
		clock = time.Now
	}
	if strings.TrimSpace(opts.StateFile) != "" {
		store := stateStore(d, "", clock)
		state, err := store.Load(opts.StateFile)
		if err != nil {
			return ManagerState{}, "", err
		}
		if piModel := strings.TrimSpace(opts.PiModel); piModel != "" {
			state.PiModel = piModel
			if err := store.Save(opts.StateFile, state); err != nil {
				return ManagerState{}, "", err
			}
		}
		return state, opts.StateFile, nil
	}
	if strings.TrimSpace(opts.PlanDir) == "" {
		return ManagerState{}, "", errors.New("plan-dir is required")
	}
	projectRoot := strings.TrimSpace(opts.ProjectRoot)
	if projectRoot == "" {
		projectRoot = "."
	}
	policy, err := initialPolicy(opts.PolicyFile, opts.PolicyPreset)
	if err != nil {
		return ManagerState{}, "", err
	}
	state, err := InitialManagerState(opts.PlanDir, projectRoot, policy)
	if err != nil {
		return ManagerState{}, "", err
	}
	if isFastPolicyPreset(opts.PolicyPreset) && strings.TrimSpace(opts.NodeID) == "" {
		opts.NodeID = string(qrspi.NodeOutline)
	}
	if err := ApplyInitOverrides(
		&state,
		InitOverrides{
			NodeID:            opts.NodeID,
			ImplementationCwd: opts.ImplementationCwd,
			PiModel:           opts.PiModel,
		},
	); err != nil {
		return ManagerState{}, "", err
	}
	state.ManagerPaneID = CaptureManagerPaneID(opts.ManagerPane)
	state.ManagerRunID = managerRunID(clock())
	root, err := stateRoot(d)
	if err != nil {
		return ManagerState{}, "", err
	}
	store := stateStore(d, root, clock)
	key := LockKey{RepoID: state.RepoID, CanonicalPlanDir: state.CanonicalPlanDir}
	if _, err := store.AcquireLock(ctx, key, state.ManagerRunID, lockTTL); err != nil {
		return ManagerState{}, "", err
	}
	stateFile := StatePath(root, key, state.ManagerRunID)
	if err := store.Save(stateFile, state); err != nil {
		return ManagerState{}, "", err
	}
	return state, stateFile, nil
}

func selectLaunchNode(state ManagerState, opts StartNextOptions) (wruntime.Node, error) {
	def, err := Definition()
	if err != nil {
		return wruntime.Node{}, err
	}
	nodeID := wruntime.NodeID(strings.TrimSpace(opts.NodeID))
	if nodeID == "" {
		nodeID = state.Workflow.CurrentNodeID
	}
	if nodeID == "" {
		nodeID = def.Start
	}
	node, ok := def.Nodes[nodeID]
	if !ok {
		return wruntime.Node{}, fmt.Errorf("node %q is not in QRSPI definition", nodeID)
	}
	return node, nil
}

func defaultChildCwd(
	state ManagerState,
	nodeID wruntime.NodeID,
	override string,
) (string, error) {
	if cwd := strings.TrimSpace(override); cwd != "" {
		return cwd, nil
	}
	switch nodeID {
	case "implement", "review-implementation", "verify":
		if cwd := strings.TrimSpace(state.ImplementationCwd); cwd != "" {
			return cwd, nil
		}
	}
	if cwd := strings.TrimSpace(state.SourceCwd); cwd != "" {
		return cwd, nil
	}
	return "", errors.New("child cwd is required")
}

func renderPromptForNode(
	state ManagerState,
	node wruntime.Node,
	planDir string,
	launch *ChildLaunchIntent,
) (string, error) {
	manifest, err := LoadManifest(state.SourceCwd)
	if err != nil {
		return "", err
	}
	return RenderStagePrompt(PromptContext{
		Node:       node,
		State:      state,
		PlanDir:    planDir,
		Manifest:   manifest,
		LastResult: state.Workflow.LastResult,
		Launch:     launch,
	})
}

func WriteStagePromptFile(
	ctx context.Context,
	state ManagerState,
	node wruntime.Node,
	opts PromptFileOptions,
) (string, error) {
	select {
	case <-ctx.Done():
		return "", ctx.Err()
	default:
	}
	prompt, err := renderPromptForNode(state, node, state.CanonicalPlanDir, opts.Launch)
	if err != nil {
		return "", err
	}
	when := opts.Timestamp
	if when.IsZero() {
		when = time.Now()
	}
	path := promptPathFor(opts.StateFile, node.ID, when)
	if err := writeFileAtomically(path, []byte(prompt), 0o644); err != nil {
		return "", err
	}
	return path, nil
}

func promptPathFor(stateFile string, nodeID wruntime.NodeID, timestamp time.Time) string {
	stamp := timestamp.UTC().Format("20060102T150405.000000000Z")
	return filepath.Join(
		filepath.Dir(stateFile),
		"prompts",
		fmt.Sprintf("%s-%s.md", nodeID, stamp),
	)
}

func writeFileAtomically(path string, data []byte, perm os.FileMode) error {
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	tmp, err := os.CreateTemp(filepath.Dir(path), ".tmp-*")
	if err != nil {
		return err
	}
	tmpName := tmp.Name()
	defer func() { _ = os.Remove(tmpName) }()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		return err
	}
	if err := tmp.Chmod(perm); err != nil {
		_ = tmp.Close()
		return err
	}
	if err := tmp.Close(); err != nil {
		return err
	}
	return os.Rename(tmpName, path)
}

import { execFile } from "node:child_process";
import { readFile } from "node:fs/promises";
import { dirname } from "node:path";
import { promisify } from "node:util";
import type { ContextUsage, ExtensionAPI, ExtensionCommandContext } from "@earendil-works/pi-coding-agent";

const execFileAsync = promisify(execFile);
const maxCLIOutputBytes = 1024 * 1024;

type QManagerAction = "start-next" | "continue";

type ParsedArgs = {
	action: QManagerAction;
	passthrough: string[];
};

type QManagerCLIResult = {
	exitCode: number;
	stdout: string;
	stderr: string;
	compaction: QManagerCompactionSignal;
};

type QManagerCompactionSignal = {
	started: boolean;
	handoffPath?: string;
	readyCommand?: string;
};

type ExecError = Error & { code?: unknown; stdout?: unknown; stderr?: unknown };

export default function qManagerParentExtension(pi: ExtensionAPI): void {
	pi.registerCommand("q-manager", {
		description: "Start q-manager from conversation context, or run an explicit start-next/continue operation",
		getArgumentCompletions: (prefix) => {
			const actions = ["start-next", "continue"];
			const matches = actions.filter((action) => action.startsWith(prefix.trim()));
			return matches.length > 0 ? matches.map((action) => ({ value: action, label: action })) : null;
		},
		handler: async (args, ctx) => {
			let parsed: ParsedArgs | undefined;
			try {
				parsed = parseArgs(args);
			} catch (error) {
				ctx.ui.notify(error instanceof Error ? error.message : String(error), "error");
				return;
			}

			if (!parsed) {
				await startManagerAgent(pi, args, ctx);
				return;
			}

			const usageFlags = usageFlagsFromContext(ctx.getContextUsage());
			const passthrough = parsed.passthrough.map((arg) => expandShellVariables(arg, ctx.cwd));
			const result = await runQManagerCLI(parsed.action, passthrough, usageFlags, ctx.cwd);
			publishCLIResult(ctx, result);

			if (result.exitCode !== 0) {
				ctx.ui.notify("q-manager CLI failed; parent compaction skipped", "error");
				return;
			}
			if (result.compaction.started) {
				compactParent(ctx, result.compaction);
			}
		},
	});
}

function parseArgs(args: string): ParsedArgs | undefined {
	const trimmed = args.trim();
	const firstToken = trimmed.match(/^\S+/)?.[0];
	if (firstToken !== "start-next" && firstToken !== "continue") return undefined;

	const parts = splitArgs(trimmed);
	const action = parts.shift() as QManagerAction;
	return { action, passthrough: parts };
}

async function startManagerAgent(pi: ExtensionAPI, args: string, ctx: ExtensionCommandContext): Promise<void> {
	const skill = pi.getCommands().find((command) => command.source === "skill" && command.name === "skill:q-manager");
	if (!skill) throw new Error("q-manager skill is not loaded");

	const skillText = await readFile(skill.sourceInfo.path, "utf8");
	const skillBody = skillText.replace(/^---\r?\n[\s\S]*?\r?\n---\r?\n?/, "").trim();
	const startupInput =
		args.trim() ||
		"Start or resume q-manager from the current conversation. Infer the next graph-safe action from the latest available QRSPI result or manager wake.";
	const prompt = `<skill name="q-manager" location="${skill.sourceInfo.path}">\nReferences are relative to ${dirname(skill.sourceInfo.path)}.\n\n${skillBody}\n</skill>\n\nManager startup input:\n${startupInput}`;

	if (ctx.isIdle()) {
		pi.sendUserMessage(prompt);
	} else {
		pi.sendUserMessage(prompt, { deliverAs: "steer" });
	}
}

function splitArgs(input: string): string[] {
	const args: string[] = [];
	let current = "";
	let quote: '"' | "'" | undefined;
	let escaping = false;

	for (const char of input) {
		if (escaping) {
			current += char;
			escaping = false;
			continue;
		}
		if (char === "\\") {
			escaping = true;
			continue;
		}
		if (quote) {
			if (char === quote) {
				quote = undefined;
			} else {
				current += char;
			}
			continue;
		}
		if (char === '"' || char === "'") {
			quote = char;
			continue;
		}
		if (/\s/.test(char)) {
			if (current !== "") {
				args.push(current);
				current = "";
			}
			continue;
		}
		current += char;
	}
	if (escaping) current += "\\";
	if (quote) throw new Error("unterminated quoted argument");
	if (current !== "") args.push(current);
	return args;
}

function expandShellVariables(arg: string, cwd: string): string {
	return arg.replace(/\$\{([A-Za-z_][A-Za-z0-9_]*)\}|\$([A-Za-z_][A-Za-z0-9_]*)/g, (match, braced, bare) => {
		const name = String(braced ?? bare);
		if (name === "PWD") return cwd;
		return process.env[name] ?? "";
	});
}

function usageFlagsFromContext(usage: ContextUsage | undefined): string[] {
	if (!usage) return [];
	if (usage.percent !== null) {
		return ["--manager-usage-percent", usage.percent.toFixed(1), "--manager-usage-source", "pi-extension-context"];
	}
	if (usage.tokens !== null && usage.contextWindow > 0) {
		return [
			"--manager-usage-tokens",
			String(usage.tokens),
			"--manager-usage-window",
			String(usage.contextWindow),
			"--manager-usage-source",
			"pi-extension-context",
		];
	}
	return [];
}

async function runQManagerCLI(
	action: QManagerAction,
	args: string[],
	usageFlags: string[],
	cwd: string,
): Promise<QManagerCLIResult> {
	const bin = process.env.VAMOS_Q_MANAGER_BIN?.trim() || "vamos";
	const cliArgs = ["qrspi", action, ...args, ...usageFlags];
	try {
		const { stdout, stderr } = await execFileAsync(bin, cliArgs, { cwd, maxBuffer: maxCLIOutputBytes });
		return { exitCode: 0, stdout, stderr, compaction: parseCompactionSignal(stdout) };
	} catch (error) {
		if (isExecError(error)) {
			const stdout = String(error.stdout ?? "");
			const stderr = String(error.stderr ?? "");
			const exitCode = typeof error.code === "number" ? error.code : 1;
			return { exitCode, stdout, stderr, compaction: parseCompactionSignal(stdout) };
		}
		throw error;
	}
}

function isExecError(error: unknown): error is ExecError {
	return error instanceof Error && ("stdout" in error || "stderr" in error || "code" in error);
}

function parseCompactionSignal(stdout: string): QManagerCompactionSignal {
	if (!stdout.split(/\r?\n/).some((line) => line.trim() === "q-manager-parent-compact: started")) {
		return { started: false };
	}
	return {
		started: true,
		handoffPath: findLineValue(stdout, "handoff:"),
		readyCommand: findLineValue(stdout, "ready:"),
	};
}

function findLineValue(stdout: string, prefix: string): string | undefined {
	for (const line of stdout.split(/\r?\n/)) {
		if (line.startsWith(prefix)) return line.slice(prefix.length).trim() || undefined;
	}
	return undefined;
}

function publishCLIResult(ctx: ExtensionCommandContext, result: QManagerCLIResult): void {
	const stdoutLine = firstSignificantLine(result.stdout);
	if (stdoutLine) ctx.ui.notify(`q-manager: ${stdoutLine}`, result.exitCode === 0 ? "info" : "error");

	const stderrLine = firstSignificantLine(result.stderr);
	if (stderrLine) ctx.ui.notify(`q-manager stderr: ${stderrLine}`, result.exitCode === 0 ? "warning" : "error");
}

function firstSignificantLine(text: string): string | undefined {
	return text
		.split(/\r?\n/)
		.map((line) => line.trim())
		.find((line) => line.length > 0);
}

function compactParent(ctx: ExtensionCommandContext, signal: QManagerCompactionSignal): void {
	const ready = signal.readyCommand ?? "vamos qrspi manager-ready --state-file <state> --manager-pane $TMUX_PANE";
	const handoff = signal.handoffPath ?? "the q-manager operational handoff printed above";
	ctx.compact({
		customInstructions: `Read q-manager operational handoff: ${handoff}.\nAfter compaction, run exactly once:\n${ready}\nThen follow any flushed q_manager_child_wake.`,
		onComplete: () => ctx.ui.notify("q-manager parent compaction complete; run manager-ready", "info"),
		onError: (error) => ctx.ui.notify(`q-manager parent compaction failed: ${error.message}`, "error"),
	});
	ctx.ui.notify("q-manager parent compaction started", "info");
}

import { spawn } from "node:child_process";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname } from "node:path";

async function writeJson(path, value) {
  if (!path) return;
  await mkdir(dirname(path), { recursive: true });
  await writeFile(path, `${JSON.stringify(value, null, 2)}\n`, "utf8");
}

async function readJson(path) {
  if (!path) return null;
  try {
    return JSON.parse(await readFile(path, "utf8"));
  } catch (error) {
    if (error && error.code === "ENOENT") return null;
    return null;
  }
}

async function touch(path) {
  if (!path) return;
  await mkdir(dirname(path), { recursive: true });
  await writeFile(path, "", "utf8");
}

async function runChildComplete() {
  const stateFile = process.env.Q_MANAGER_STATE_FILE || "";
  const childID = process.env.Q_MANAGER_CHILD_ID || "";
  if (!stateFile || !childID) return null;
  return new Promise((resolve) => {
    const child = spawn(
      "vamos",
      [
        "qrspi",
        "child-complete",
        "--state-file",
        stateFile,
        "--child-id",
        childID,
        "--output",
        "json",
      ],
      { stdio: ["ignore", "pipe", "pipe"] },
    );
    let stdout = "";
    child.stdout.on("data", (chunk) => {
      stdout += chunk.toString();
    });
    child.on("exit", () => {
      try {
        resolve(JSON.parse(stdout));
      } catch {
        resolve(null);
      }
    });
    child.on("error", () => resolve(null));
  });
}

function shouldWakeManager(validation) {
  if (!validation) return false;
  return (
    validation.validated === true ||
    validation.managerNeeded === true ||
    validation.retryExhausted === true
  );
}

export default function qManagerChildExtension(pi) {
  const key = Symbol.for("vamos.q_manager_child_extension.loaded");
  if (globalThis[key]) return;
  globalThis[key] = true;

  pi.on("agent_end", async () => {
    const produced = await runChildComplete();
    const validation =
      produced ||
      (await readJson(process.env.Q_MANAGER_VALIDATED_STATUS_PATH || ""));
    const status = {
      event: "agent_end",
      stage: process.env.Q_MANAGER_STAGE || "",
      childId: process.env.Q_MANAGER_CHILD_ID || "",
      managerRunId: process.env.Q_MANAGER_MANAGER_RUN_ID || "",
      stateFile: process.env.Q_MANAGER_STATE_FILE || "",
      planDir: process.env.Q_MANAGER_PLAN_DIR || "",
      sessionId:
        process.env.Q_MANAGER_SESSION_ID || process.env.SESSION_ID || "",
      sessionDir:
        process.env.Q_MANAGER_SESSION_DIR || process.env.SESSION_DIR || "",
      sessionPath: process.env.SESSION_PATH || "",
      finishedAt: new Date().toISOString(),
      wakeTarget: process.env.Q_MANAGER_PARENT_PANE || "",
      wakeMode: process.env.Q_MANAGER_WAKE_MODE || "validated-only",
      validationStatusPath: process.env.Q_MANAGER_VALIDATED_STATUS_PATH || "",
      activeChildGeneration: validation?.childGeneration || "",
      helperProducedStatus: produced !== null,
      managerWakeSuppressed: !shouldWakeManager(validation),
      wakeDeliveryMode: validation?.wake?.mode || "",
      wakeDeliveryReason: validation?.wake?.reason || "",
    };
    await writeJson(process.env.Q_MANAGER_STATUS_PATH, status);
    await touch(process.env.Q_MANAGER_DONE_PATH);
  });
}

package qrspicmd

import (
	"context"
	"fmt"
	"strings"
)

type ManagerPaneAdoptionCommand string

const (
	ManagerPaneAdoptionStartNext    ManagerPaneAdoptionCommand = "start-next"
	ManagerPaneAdoptionContinue     ManagerPaneAdoptionCommand = "continue"
	ManagerPaneAdoptionManagerReady ManagerPaneAdoptionCommand = "manager-ready"
)

type ManagerPaneAdoptionOptions struct {
	StateFile    string
	Command      ManagerPaneAdoptionCommand
	ExplicitPane string
	CurrentPane  string
}

type PaneLiveness struct {
	PaneID  string
	Checked bool
	Exists  bool
	Error   string
}

type ManagerPaneAdoptionResult struct {
	State       ManagerState
	Changed     bool
	AdoptedPane string
	Reason      string
	Evidence    []string
	ActionCard  *ManagerActionCard
}

func ResolveManagerPaneAdoption(
	ctx context.Context,
	state ManagerState,
	opts ManagerPaneAdoptionOptions,
	d deps,
) (ManagerPaneAdoptionResult, error) {
	opts.StateFile = strings.TrimSpace(opts.StateFile)
	opts.ExplicitPane = strings.TrimSpace(opts.ExplicitPane)
	opts.CurrentPane = strings.TrimSpace(opts.CurrentPane)

	result := ManagerPaneAdoptionResult{State: state}
	stored := strings.TrimSpace(state.ManagerPaneID)
	delivery := strings.TrimSpace(state.Delivery.ManagerPaneID)
	selected := firstNonEmpty(delivery, stored)
	selectedLive := managerPaneLiveness(ctx, selected, d)
	storedLive := managerPaneLiveness(ctx, stored, d)
	deliveryLive := managerPaneLiveness(ctx, delivery, d)
	currentLive := managerPaneLiveness(ctx, opts.CurrentPane, d)
	result.Evidence = managerPaneEvidence(
		state,
		opts,
		storedLive,
		deliveryLive,
		currentLive,
	)

	if opts.ExplicitPane != "" {
		result.State.ManagerPaneID = opts.ExplicitPane
		if shouldRebindDeliveryPane(state, opts.ExplicitPane, true, selectedLive) {
			result.State.Delivery.ManagerPaneID = opts.ExplicitPane
		}
		result.Changed = result.State.ManagerPaneID != state.ManagerPaneID ||
			result.State.Delivery.ManagerPaneID != state.Delivery.ManagerPaneID
		result.AdoptedPane = opts.ExplicitPane
		result.Reason = "explicit_manager_pane"
		result.Evidence = append(result.Evidence, "adoption: explicit --manager-pane")
		return result, nil
	}

	if opts.CurrentPane == "" {
		result.Reason = "no_current_manager_pane"
		return result, nil
	}
	if currentLive.Checked && !currentLive.Exists {
		result.Reason = "current_manager_pane_unavailable"
		result.Evidence = append(
			result.Evidence,
			"adoption: current TMUX_PANE unavailable; not adopted",
		)
		return result, nil
	}
	if selected != "" && selected == opts.CurrentPane {
		if state.ManagerPaneID == "" {
			result.State.ManagerPaneID = opts.CurrentPane
			result.Changed = true
		}
		if shouldRebindDeliveryPane(state, opts.CurrentPane, false, selectedLive) &&
			state.Delivery.ManagerPaneID != opts.CurrentPane {
			result.State.Delivery.ManagerPaneID = opts.CurrentPane
			result.Changed = true
		}
		result.AdoptedPane = opts.CurrentPane
		result.Reason = "current_matches_manager_pane"
		return result, nil
	}
	canAutoAdopt := managerPaneAutoAdoptionAllowed(state, selectedLive)
	if selected != "" && selectedLive.Exists && !canAutoAdopt {
		result.ActionCard = buildManagerPaneActionCard(
			state,
			opts,
			result.Evidence,
			ActionManagerPaneAdoptionRequired,
		)
		result.Reason = "live_manager_pane_conflict"
		return result, nil
	}
	if canAutoAdopt {
		result.State.ManagerPaneID = opts.CurrentPane
		if shouldRebindDeliveryPane(state, opts.CurrentPane, false, selectedLive) {
			result.State.Delivery.ManagerPaneID = opts.CurrentPane
		}
		result.Changed = result.State.ManagerPaneID != state.ManagerPaneID ||
			result.State.Delivery.ManagerPaneID != state.Delivery.ManagerPaneID
		result.AdoptedPane = opts.CurrentPane
		result.Reason = "safe_current_pane_adoption"
		result.Evidence = append(result.Evidence, "adoption: safe current TMUX_PANE")
		return result, nil
	}
	return result, nil
}

func managerPaneAutoAdoptionAllowed(state ManagerState, selected PaneLiveness) bool {
	if strings.EqualFold(state.Delivery.Status, "compacting") ||
		state.Delivery.QueuedWake != nil {
		return true
	}
	selectedPane := strings.TrimSpace(selected.PaneID)
	if selectedPane == "" {
		return true
	}
	if !selected.Checked || !selected.Exists {
		return true
	}
	return false
}

func shouldRebindDeliveryPane(
	state ManagerState,
	adoptedPane string,
	explicit bool,
	selected PaneLiveness,
) bool {
	if strings.TrimSpace(adoptedPane) == "" {
		return false
	}
	if explicit {
		return true
	}
	if strings.TrimSpace(state.Delivery.ManagerPaneID) == "" {
		return true
	}
	if strings.EqualFold(state.Delivery.Status, "compacting") ||
		state.Delivery.QueuedWake != nil {
		return true
	}
	return selected.Checked &&
		strings.TrimSpace(
			selected.PaneID,
		) == strings.TrimSpace(
			state.Delivery.ManagerPaneID,
		) &&
		!selected.Exists
}

func managerPaneLiveness(ctx context.Context, pane string, d deps) PaneLiveness {
	pane = strings.TrimSpace(pane)
	live := PaneLiveness{PaneID: pane}
	if pane == "" {
		return live
	}
	live.Checked = true
	ok, err := tmuxClient(d).PaneExists(ctx, TmuxPane{ID: pane})
	live.Exists = ok && err == nil
	if err != nil {
		live.Error = err.Error()
	}
	return live
}

func buildManagerPaneActionCard(
	state ManagerState,
	opts ManagerPaneAdoptionOptions,
	evidence []string,
	kind string,
) *ManagerActionCard {
	summary := "q-manager parent pane adoption needs explicit operator intent"
	recommended := "rerun from the intended parent tmux pane with --manager-pane"
	if kind == ActionManagerPaneUnavailable {
		summary = "q-manager manager pane unavailable; wake queued for explicit parent recovery"
		recommended = "run manager-ready from the intended parent tmux pane"
	}
	return &ManagerActionCard{
		Kind:              kind,
		Severity:          "warning",
		Summary:           summary,
		Evidence:          evidence,
		RecommendedAction: recommended,
		SafeCommand:       managerPaneSafeCommand(opts),
		ContinueCommand:   continueCommand(opts.StateFile),
		RequiresHuman:     false,
	}
}

func managerPaneSafeCommand(opts ManagerPaneAdoptionOptions) string {
	stateFile := strings.TrimSpace(opts.StateFile)
	switch opts.Command {
	case ManagerPaneAdoptionStartNext:
		return fmt.Sprintf(
			"vamos qrspi start-next --state-file %s --manager-pane \"$TMUX_PANE\"",
			stateFile,
		)
	case ManagerPaneAdoptionManagerReady:
		return fmt.Sprintf(
			"vamos qrspi manager-ready --state-file %s --manager-pane \"$TMUX_PANE\"",
			stateFile,
		)
	default:
		return fmt.Sprintf(
			"vamos qrspi continue --state-file %s --manager-pane \"$TMUX_PANE\"",
			stateFile,
		)
	}
}

func managerPaneEvidence(
	state ManagerState,
	opts ManagerPaneAdoptionOptions,
	stored, delivery, current PaneLiveness,
) []string {
	evidence := []string{
		fmt.Sprintf("state file: %s", opts.StateFile),
		fmt.Sprintf("command: %s", opts.Command),
		fmt.Sprintf(
			"stored manager pane: %s",
			firstNonEmpty(state.ManagerPaneID, "<empty>"),
		),
		fmt.Sprintf(
			"delivery manager pane: %s",
			firstNonEmpty(state.Delivery.ManagerPaneID, "<empty>"),
		),
		fmt.Sprintf("current TMUX_PANE: %s", firstNonEmpty(opts.CurrentPane, "<empty>")),
		fmt.Sprintf(
			"delivery status: %s",
			firstNonEmpty(state.Delivery.Status, "<empty>"),
		),
		fmt.Sprintf("queued wake: %t", state.Delivery.QueuedWake != nil),
	}
	for _, live := range []PaneLiveness{stored, delivery, current} {
		if !live.Checked {
			continue
		}
		line := fmt.Sprintf("pane liveness: %s exists=%t", live.PaneID, live.Exists)
		if live.Error != "" {
			line += " error=" + live.Error
		}
		evidence = append(evidence, line)
	}
	return evidence
}

