	used := func(id string) bool {
		return (state.ActiveChild != nil && state.ActiveChild.ID == id) ||
			(state.PendingCleanupChild != nil && state.PendingCleanupChild.ID == id)
	}
	if !used(base) {
		return base
	}
	for suffix := 2; ; suffix++ {
		candidate := fmt.Sprintf("%s-%d", base, suffix)
		if !used(candidate) {
			return candidate
		}
	}
}

